quickCss:
*,
*::before,
*::after {
    border-radius: 0 !important;
    font-family: "DepartureMono Nerd Font Propo" !important;
    font-weight: 500 !important;
}
[class*="guilds"] [class*="wrapper"],
[class*="guilds"] [class*="childWrapper"],
[class*="guilds"] svg,
[class*="guilds"] img {
    border-radius: 50% !important;
}
[class*="numberBadge"],
[class*="unreadBadge"] {
    border-radius: 50% !important;
    min-width: 18px !important;
    height: 18px !important;
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    padding: 0 !important;
}
[class*="avatar"] img,
[class*="avatar"] svg,
[class*="avatar"] {
    border-radius: 50% !important;
}
[class*="guilds"] [class*="pill"] span {
    width: 8px !important;
    height: 8px !important;
    border-radius: 50% !important;
    transition: height 180ms ease, width 180ms ease, border-radius 180ms ease;
}
[class*="guilds"] [class*="listItem"]:hover [class*="pill"] span {
    width: 9px !important;
    height: 20px !important;
    border-radius: 100% !important;
}
[class*="guilds"] [class*="listItem"]:has([aria-selected="true"]) [class*="pill"] span {
    width: 8px !important;
    height: 30px !important;
    border-radius: 6px !important;
}
[class*="guilds"] [class*="pill"] {
    align-items: center !important;
}
[class*="guilds"] [class*="folder"] {
    border-radius: 0 !important;
    background: transparent;
}
li[class*="containerDefault"] [class*="unread"] {
    display: none !important;
}
div[class*="circleIconButton"] {
    border-radius: 50% !important;
}
div[class*="circleIconButton"] svg {
    border-radius: 50% !important;
}
.panels__5e434 {
    right: 0;
    left: 0;
    bottom: 0;
    width: auto !important;
}

/* Gradient — small consistent fade in both modes */
[class*="chatTypingGradient"],
[class*="chatGradientBase"] {
    height: 16px !important;
    min-height: 0 !important;
}

/* Typing/slowmode bar — tight, no bulk */
[class*="typing"][class*="base"] {
    min-height: 0 !important;
    height: auto !important;
    padding: 2px 8px !important;
    margin: 0 !important;
    background: transparent !important;
    box-shadow: none !important;
}

/* Hide typing dots, keep slowmode text */
[class*="typingDots"] {
    display: none !important;
}

[class*="cooldownText"] {
    display: inline-flex !important;
    align-items: center !important;
    gap: 4px !important;
}

/* Spacer — consistent in both normal and slowmode */
[class*="scrollerSpacer"] {
    height: 18px !important;
    min-height: 0 !important;
    flex: 0 0 36px !important;
}

/* Last item padding for normal mode without scrollerSpacer */
[class*="scrollerInner"] > li:last-child,
[class*="scrollerInner"] > [class*="messageListItem"]:last-child {
    padding-bottom: 36px !important;
}

/* Message input only — target channelTextArea specifically */
[class*="channelTextArea"] {
    position: sticky !important;
    bottom: 0 !important;
    left: 0 !important;
    right: 0 !important;
    width: 100% !important;
    max-width: 100% !important;
    margin: 0 !important;
    padding-left: 0 !important;
    padding-right: 0 !important;
    box-sizing: border-box !important;
    align-self: stretch !important;
}

/* Follow container — sticky to bottom, preserve its natural height */
[class*="formWithLoadedChatInput"],
form[class*="form_"] {
    position: sticky !important;
    bottom: 0 !important;
    left: 0 !important;
    right: 0 !important;
    width: 100% !important;
    max-width: 100% !important;
    margin: 0 !important;
    padding-left: 0 !important;
    padding-right: 0 !important;
    box-sizing: border-box !important;
    z-index: 1 !important;
}

/* Jump to present bar — full width, flush to bottom above input, no height change */
[class*="jumpToPresentBar"] {
    left: 0 !important;
    right: 0 !important;
    bottom: 0 !important;
    width: 100% !important;
    max-width: 100% !important;
    margin: 0 !important;
    box-sizing: border-box !important;
}

/* New messages bar — same treatment */
[class*="newMessagesBar"] {
    left: 0 !important;
    right: 0 !important;
    width: 100% !important;
    max-width: 100% !important;
    margin: 0 !important;
    box-sizing: border-box !important;
}

/* Follow container bar — edge to edge */
[class*="followContainer"] {
    position: sticky !important;
    bottom: 0 !important;
    left: 0 !important;
    right: 0 !important;
    width: 100% !important;
    max-width: 100% !important;
    margin: 0 !important;
    box-sizing: border-box !important;
}

